={{
{
  "model": "llama-3.3-70b-versatile",
  "messages": [
    {
      "role": "system",
      "content": "Parse OCR table rows into pipe-delimited records. Each input line is one row: space-separated x0:word tokens sorted left-to-right. Columns left-to-right: SN, EMPID, NAME, GRADE, CURRENT, NEW, FUNCTION, REMARKS. Multi-word values (names, plant/city names like 'DABHOL KLL') stay in one field. Grade is always 2 chars: E or S + digit. Output exactly one line per input row: SN|EMPID|NAME|GRADE|CURRENT|NEW|FUNCTION|REMARKS. Leave a field blank if absent. No headers, no explanations, no markdown."
    },
    {
      "role": "user",
      "content": `${$json.rows}`
    }
  ],
  "temperature": 0,
  "response_format": { "type": "text" }
}
}}

parameters.jsCode:
// Enable "Execute Once" in node Settings so this runs on the full batch,
// not once per PDF item.
const items = $input.all();

const plantSet = new Set();
for (const item of items) {
  const transfers = item.json.transfers || [];
  for (const transfer of transfers) {
    if (transfer.current_location) {
      plantSet.add(
        transfer.current_location
          .replace(/\s+Plant$/i, "")
          .trim()
      );
    }
    if (transfer.new_location) {
      plantSet.add(
        transfer.new_location
          .replace(/\s+Plant$/i, "")
          .trim()
      );
    }
  }
}

return [...plantSet].map(name => {
  const firstPart = name.split(/[\s-]+/)[0];
  return {
    json: {
      plant_name: name,
      search_query: `${firstPart}, India`
    }
  };
});

const MANUAL_COORDINATES = {
  "ADIYAKAMANGALAM": { latitude: 10.761814, longitude: 79.678294 },
};

const plantName = $('Code in JavaScript11').item.json.plant_name;
const location = $json.results[0];

// Manual override takes priority — skip geocoding result entirely if we have one
if (MANUAL_COORDINATES[plantName]) {
  return {
    json: {
      plant_name: plantName,
      latitude: MANUAL_COORDINATES[plantName].latitude,
      longitude: MANUAL_COORDINATES[plantName].longitude,
      geocode_failed: false,
      manually_corrected: true,
      originalData: $('Code in JavaScript11').item.json.originalData
    }
  };
}

if (location.components._type === 'country') {
  return {
    json: {
      plant_name: plantName,
      latitude: null,
      longitude: null,
      geocode_failed: true,
      originalData: $('Code in JavaScript11').item.json.originalData
    }
  };
}

return {
  json: {
    plant_name: plantName,
    latitude: Number(location.geometry.lat),
    longitude: Number(location.geometry.lng),
    geocode_failed: false,
    originalData: $('Code in JavaScript11').item.json.originalData
  }
};

const items = $input.all();
const coordMap = {};
for (const item of items) {
  coordMap[item.json.plant_name] = {
    latitude: item.json.latitude,
    longitude: item.json.longitude
  };
}

const allTransfers = $('Parse LLM output').first().json?.transfers ?? [];

const transfers = allTransfers.map(t => {
  const fromKey = t.current_location;
  const toKey = t.new_location;
  return {
    employee_id: t.emp_no,
    employee_name: t.name,
    from_location: fromKey,
    to_location: toKey,
    from_coords: coordMap[fromKey] ?? null,
    to_coords: coordMap[toKey] ?? null,
  };
});

return [{ json: { transfers } }];

const result = $input.first().json // response is an array with one object
const rows = [];

// Two-way swaps
for (const swap of result.two_way_swaps ?? []) {
  for (const t of swap.transfers) {
    rows.push({
      type: "2-way swap",
      cycle_id: swap.cycle_id,
      employee_id: t.employee_id,
      employee_name: t.employee_name,
      from_location: t.from_location,
      to_location: t.to_location,
      reason: swap.reason
    });
  }
}

// Three-way swaps
for (const swap of result.three_way_swaps ?? []) {
  for (const t of swap.transfers) {
    rows.push({
      type: "3-way swap",
      cycle_id: swap.cycle_id,
      employee_id: t.employee_id,
      employee_name: t.employee_name,
      from_location: t.from_location,
      to_location: t.to_location,
      reason: swap.reason
    });
  }
}

// Surplus transfers (bulk city-to-city shipments)
for (const s of result.surplus_transfers ?? []) {
  rows.push({
    type: "Surplus transfer",
    cycle_id: "",
    employee_id: "",
    employee_name: "",
    from_location: s.from_location,
    to_location: s.to_location,
    quantity: s.quantity,
    reason: "City needs PC — surplus routing"
  });
}

// Unresolved transfers
for (const t of result.unresolved_transfers ?? []) {
  rows.push({
    type: "Unresolved",
    cycle_id: "",
    employee_id: t.employee_id,
    employee_name: t.employee_name,
    from_location: t.from_location,
    to_location: t.to_location,
    reason: "No match found"
  });
}

return rows.map(r => ({ json: r }));

const staticData = $getWorkflowStaticData('global');
const items = $input.all();

for (const item of items) {
  const name = item.json.plant_name;
  staticData.geocodeCache[name] = {
    latitude: item.json.latitude,
    longitude: item.json.longitude
  };
}

return items;

const binaryKeys = Object.keys($input.first().binary || {});
return binaryKeys.map(key => ({
  json: { sourceFile: key },
  binary: { data: $input.first().binary[key] }
}));

// Mode: "Run Once for All Items"
const items = $input.all(); // one item per PDF document
const pageItems = [];

for (const item of items) {
  const doc = item.json; // { source_filename, page_width, num_pages, pages, total_candidate_rows }
  for (const page of doc.pages) {
    pageItems.push({
      json: {
        source_filename: doc.source_filename,
        page_number: page.page_number,
        rows: page.rows
      }
    });
  }
}

return pageItems;

const items = $input.all();
let allRecords = [];
for (const item of items) {
  const text = item.json.choices[0].message.content.trim(); // adjust path to match your LLM node's output shape
  const lines = text.split("\n").filter(l => l.trim());
  for (const line of lines) {
    const [sn, emp_no, name, grade, current, newloc, func, remarks] = line.split("|");
    allRecords.push({ sn, emp_no, name, grade, current_location: current, new_location: newloc, new_function: func, remarks });
  }
}
return [{ json: { transfers: allRecords } }];
